const { ethers } = require('ethers');

const PRIVATE_KEY = 'your-private-key-here';
const RPC_URL = 'https://mainnet.infura.io/v3/your-infura-key';

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function getBalance(address) {
    const balance = await provider.getBalance(address);
    return ethers.formatEther(balance);
}

async function sendETH(toAddress, amountInEther) {
    const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString())
    };
    
    const transaction = await wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    return receipt;
}

async function sendETHWithGasLimit(toAddress, amountInEther, gasLimit) {
    const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString()),
        gasLimit: gasLimit
    };
    
    const transaction = await wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    return receipt;
}

async function getContractInstance(contractAddress, abi) {
    return new ethers.Contract(contractAddress, abi, wallet);
}

async function callContractMethod(contractAddress, abi, methodName, params = []) {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const result = await contract[methodName](...params);
    return result;
}

async function sendContractTransaction(contractAddress, abi, methodName, params = [], options = {}) {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const tx = await contract[methodName](...params, options);
    const receipt = await tx.wait();
    return receipt;
}

async function estimateGas(contractAddress, abi, methodName, params = []) {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const gasEstimate = await contract[methodName].estimateGas(...params);
    return gasEstimate;
}

async function getTransactionReceipt(txHash) {
    const receipt = await provider.getTransactionReceipt(txHash);
    return receipt;
}

async function getCurrentGasPrice() {
    const feeData = await provider.getFeeData();
    return {
        gasPrice: feeData.gasPrice,
        maxFeePerGas: feeData.maxFeePerGas,
        maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
    };
}

async function sendERC20Token(tokenAddress, toAddress, amount, decimals = 18) {
    const erc20ABI = [
        'function transfer(address to, uint256 amount) returns (bool)',
        'function balanceOf(address account) view returns (uint256)',
        'function decimals() view returns (uint8)'
    ];
    
    const tokenContract = new ethers.Contract(tokenAddress, erc20ABI, wallet);
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    const tx = await tokenContract.transfer(toAddress, amountInWei);
    const receipt = await tx.wait();
    return receipt;
}

async function approveERC20(tokenAddress, spenderAddress, amount, decimals = 18) {
    const erc20ABI = [
        'function approve(address spender, uint256 amount) returns (bool)'
    ];
    
    const tokenContract = new ethers.Contract(tokenAddress, erc20ABI, wallet);
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    const tx = await tokenContract.approve(spenderAddress, amountInWei);
    const receipt = await tx.wait();
    return receipt;
}

async function getERC20Balance(tokenAddress, accountAddress) {
    const erc20ABI = [
        'function balanceOf(address account) view returns (uint256)',
        'function decimals() view returns (uint8)'
    ];
    
    const tokenContract = new ethers.Contract(tokenAddress, erc20ABI, provider);
    const balance = await tokenContract.balanceOf(accountAddress);
    const decimals = await tokenContract.decimals();
    return ethers.formatUnits(balance, decimals);
}

async function signMessage(message) {
    const signature = await wallet.signMessage(message);
    return signature;
}

async function signTypedData(domain, types, value) {
    const signature = await wallet.signTypedData(domain, types, value);
    return signature;
}

async function deployContract(abi, bytecode, constructorArgs = []) {
    const factory = new ethers.ContractFactory(abi, bytecode, wallet);
    const contract = await factory.deploy(...constructorArgs);
    await contract.waitForDeployment();
    return await contract.getAddress();
}

async function batchSendETH(recipients) {
    const transactions = [];
    for (const recipient of recipients) {
        const tx = await sendETH(recipient.address, recipient.amount);
        transactions.push(tx);
    }
    return transactions;
}

async function getNonce(address) {
    const nonce = await provider.getTransactionCount(address);
    return nonce;
}

async function sendRawTransaction(signedTx) {
    const tx = await provider.broadcastTransaction(signedTx);
    const receipt = await tx.wait();
    return receipt;
}

async function createSignedTransaction(toAddress, amountInEther, nonce, gasLimit, gasPrice) {
    const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString()),
        nonce: nonce,
        gasLimit: gasLimit,
        gasPrice: gasPrice
    };
    
    const signedTx = await wallet.signTransaction(tx);
    return signedTx;
}

async function waitForTransaction(txHash, confirmations = 1) {
    const receipt = await provider.waitForTransaction(txHash, confirmations);
    return receipt;
}

async function getBlockNumber() {
    const blockNumber = await provider.getBlockNumber();
    return blockNumber;
}

async function getBlock(blockNumber) {
    const block = await provider.getBlock(blockNumber);
    return block;
}

async function getTransaction(txHash) {
    const tx = await provider.getTransaction(txHash);
    return tx;
}

async function estimateTransactionCost(toAddress, amountInEther) {
    const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString())
    };
    
    const gasEstimate = await provider.estimateGas(tx);
    const feeData = await provider.getFeeData();
    const cost = gasEstimate * feeData.gasPrice;
    return ethers.formatEther(cost);
}

module.exports = {
    wallet,
    provider,
    getBalance,
    sendETH,
    sendETHWithGasLimit,
    getContractInstance,
    callContractMethod,
    sendContractTransaction,
    estimateGas,
    getTransactionReceipt,
    getCurrentGasPrice,
    sendERC20Token,
    approveERC20,
    getERC20Balance,
    signMessage,
    signTypedData,
    deployContract,
    batchSendETH,
    getNonce,
    sendRawTransaction,
    createSignedTransaction,
    waitForTransaction,
    getBlockNumber,
    getBlock,
    getTransaction,
    estimateTransactionCost
};